import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "What is voltage drop?", a: "Voltage drop is the reduction in electrical potential as current flows through a wire. All conductors have resistance, and by Ohm's Law (V = I  x  R), current flowing through resistance causes a voltage reduction. The wire heats up from the lost energy. Excessive voltage drop causes motors to run hot, lights to dim, and electronics to malfunction." },
  { q: "What is the acceptable voltage drop percentage?", a: "The NEC (National Electrical Code) recommends: maximum 3% voltage drop for branch circuits (from panel to outlet), and maximum 5% total from the service entrance to the farthest outlet. For sensitive equipment (motors, computers, medical devices), keep drop under 2%. Higher voltage drops reduce equipment lifespan, efficiency, and may void warranties." },
  { q: "How do I reduce voltage drop?", a: "Four approaches: (1) Use a larger wire gauge (lower AWG number - 10 AWG vs 12 AWG reduces resistance by ~37%). (2) Shorten the wire run - closer subpanels reduce total wire length. (3) Reduce the load (current). (4) Increase source voltage (use 240V instead of 120V where possible - same current, half the drop percentage). Doubling wire cross-section area halves resistance." },
  { q: "What wire gauge should I use for long runs?", a: "General guide for 120V single-phase at 80% load: up to 50 ft: 14 AWG (15A breaker). 50-100 ft: 12 AWG. 100-150 ft: 10 AWG. 150-200 ft: 8 AWG. Always calculate exact drop for your specific current and distance. For 240V circuits, the percentage drop is halved for the same wire size and current, so you can run longer distances on the same gauge." },
  { q: "What is the difference between single-phase and three-phase voltage drop?", a: "Single-phase voltage drop: V = 2  x  I  x  R  x  L (current travels down and back, doubling the effective wire length). Three-phase voltage drop: V = -  x  I  x  R  x  L = 1.732  x  I  x  R  x  L. Three-phase is more efficient - for the same load and wire, three-phase has ~13% less voltage drop than single-phase. Three-phase is standard for commercial and industrial applications." },
  { q: "What is AWG (American Wire Gauge)?", a: "AWG is the US standard for wire sizes. Counter-intuitively, lower AWG = thicker wire. 14 AWG is thinner than 12 AWG, which is thinner than 10 AWG. Common uses: 14 AWG = 15A circuits (outlets, lights). 12 AWG = 20A circuits (kitchen, bathroom). 10 AWG = 30A circuits (dryers, large appliances). 8 AWG = 40-50A circuits (ranges, EV chargers). Resistance decreases as gauge decreases (thicker wire)." },
  { q: "How does temperature affect voltage drop?", a: "Copper's resistivity increases with temperature - approximately 0.39% per - At 75- (the NEC temperature rating for most wire insulation), copper resistance is about 26% higher than at 20- For precise calculations in high-temperature environments or conduits running full loads, multiply the resistance values by a temperature correction factor. This calculator uses 20- (68- standard resistance values." },
  { q: "Should I use copper or aluminum wire?", a: "Copper is the standard for residential branch circuits. Aluminum is used for large feeders and service entrance (200A panel feeds, utility runs) where the lower cost and weight offset the larger sizes needed. Aluminum has ~61% the conductivity of copper - to match copper's resistance, use aluminum that is 2 AWG sizes larger (copper 12 AWG - aluminum 10 AWG). Never mix copper and aluminum connections without anti-oxidant compound and AL-rated connectors." },
];

const AWG_TABLE = [
  ["14 AWG", "3.14", "15A", "Outlets, lighting"],
  ["12 AWG", "1.98", "20A", "Kitchen, bath outlets"],
  ["10 AWG", "1.24", "30A", "Dryers, large appliances"],
  ["8 AWG", "0.778", "40-50A", "Ranges, EV chargers"],
  ["6 AWG", "0.491", "55-65A", "Subpanels, A/C"],
  ["4 AWG", "0.308", "70-85A", "Service entrance"],
  ["2 AWG", "0.194", "95-115A", "Large service feeds"],
  ["1/0 AWG", "0.122", "125-150A", "Main service entrance"],
];

const RESISTANCE: Record<string, number> = {
  "14 AWG (Copper)": 3.14, "12 AWG (Copper)": 1.98, "10 AWG (Copper)": 1.24,
  "8 AWG (Copper)": 0.778, "6 AWG (Copper)": 0.491, "4 AWG (Copper)": 0.308,
  "2 AWG (Copper)": 0.194, "1/0 AWG (Copper)": 0.122,
};

export default function VoltageDropCalculator() {
  const [wireGauge, setWireGauge] = useState("12 AWG (Copper)");
  const [current, setCurrent] = useState(15);
  const [length, setLength] = useState(50);
  const [voltage, setVoltage] = useState(120);
  const [phase, setPhase] = useState<"single" | "three">("single");

  const resistancePerK = RESISTANCE[wireGauge];
  const phaseFactor = phase === "single" ? 2 : 1.732;
  const drop = (phaseFactor * resistancePerK * current * length) / 1000;
  const pctDrop = (drop / voltage) * 100;
  const endVoltage = voltage - drop;

  return (
    <>
      <SEOHead
        title="Free Voltage Drop Calculator Online - Calculate Wire Voltage Drop Instantly | CalcHive"
        description="Free online voltage drop calculator. Calculate voltage drop across any wire run by gauge, current, length and source voltage instantly. 100% free for electricians and students, no signup required."
        canonical="/voltage-drop-calculator"
        keywords="free voltage drop calculator, voltage drop calculator online free, wire voltage drop calculator free, calculate voltage drop free, electrical voltage drop tool free"
        category="Electrical Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-yellow-600 dark:text-yellow-400 bg-yellow-50 dark:bg-yellow-950/50 px-3 py-1 rounded-full mb-4 inline-block">Electronics</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Voltage Drop Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free voltage drop calculator to calculate voltage drop free across any wire run by gauge, current, length, and source voltage. This voltage drop calculator online free also works as a wire voltage drop calculator free and electrical voltage drop tool free.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-8">
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">Wire Gauge</label>
              <select value={wireGauge} onChange={e => setWireGauge(e.target.value)} className="w-full px-4 py-3 rounded-xl border border-border bg-background text-foreground focus:outline-none focus:ring-2 focus:ring-primary/40 text-sm">
                {Object.keys(RESISTANCE).map(k => <option key={k} value={k}>{k}</option>)}
              </select>
            </div>
            <div>
              <label className="text-sm font-semibold text-foreground mb-2 block">Phase</label>
              <div className="flex gap-2">
                {[["single", "Single Phase"], ["three", "Three Phase"]].map(([v, l]) => (
                  <button key={v} onClick={() => setPhase(v as "single" | "three")} className={`flex-1 py-2 rounded-xl text-sm font-semibold border transition-all ${phase === v ? "bg-yellow-500 text-white border-yellow-500" : "bg-card text-muted-foreground border-border"}`}>{l}</button>
                ))}
              </div>
            </div>
            <SliderInput id="current" label="Current (Amps)" value={current} min={1} max={400} step={1} onChange={setCurrent} format={v => `${v} A`} testId="input-current" />
            <SliderInput id="length" label="One-Way Wire Length (ft)" value={length} min={1} max={1000} step={1} onChange={setLength} format={v => `${v} ft`} testId="input-length" helpText="Single-phase uses 2 x  length for round-trip" />
            <SliderInput id="voltage" label="Source Voltage (V)" value={voltage} min={12} max={480} step={1} onChange={setVoltage} format={v => `${v} V`} testId="input-voltage" />
          </div>
          <motion.div key={`${wireGauge}-${current}-${length}-${voltage}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className={`bg-gradient-to-br ${pctDrop > 5 ? "from-red-500 to-red-700" : pctDrop > 3 ? "from-orange-500 to-orange-700" : "from-yellow-500 to-yellow-700"} rounded-2xl p-6 mb-4 text-center shadow-lg`}>
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Voltage Drop</p>
              <p className="text-5xl font-black text-white tracking-tight" data-testid="result-drop">{drop.toFixed(2)} V</p>
              <p className="text-white/70 text-sm mt-1">{pctDrop.toFixed(2)}% drop - {pctDrop > 5 ? "EXCEEDS NEC 5% limit" : pctDrop > 3 ? "Exceeds NEC 3% recommendation" : "Within NEC recommendations"}</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[
                { label: "End Voltage", value: `${endVoltage.toFixed(2)} V` },
                { label: "% Voltage Drop", value: `${pctDrop.toFixed(2)}%`, red: pctDrop > 5, orange: pctDrop > 3 && pctDrop <= 5 },
                { label: "Wire Resistance", value: `${((resistancePerK * phaseFactor * length) / 1000).toFixed(4)}  ohm` },
              ].map(({ label, value, red, orange }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className={`text-base font-extrabold ${red ? "text-red-600 dark:text-red-400" : orange ? "text-orange-600 dark:text-orange-400" : "text-foreground"}`}>{value}</p>
                </div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Voltage Drop Across Any Wire for Free</h2>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Single-Phase: V_drop = 2  x  R  x  I  x  L / 1000</p>
            <p>Three-Phase: V_drop = -  x  R  x  I  x  L / 1000</p>
            <p>% Drop = (V_drop / V_source)  x  100</p>
            <p>End Voltage = V_source - V_drop</p>
            <p className="text-xs text-muted-foreground mt-2">R = resistance in ohms per 1,000 feet (ohms/kft)</p>
            <p className="text-xs text-muted-foreground">L = one-way wire length in feet - I = current in amps</p>
            <p className="text-xs text-muted-foreground">NEC: max 3% branch circuit, 5% total (service to outlet)</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">How Wire Gauge Current and Length Affect Voltage Drop</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["AWG Size", "Resistance ( ohm/kft)", "Max Ampacity", "Typical Use"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {AWG_TABLE.map(([gauge, res, amps, use]) => {
                  const selected = wireGauge.startsWith(gauge.replace(" AWG", "").trim() + " AWG");
                  return (
                    <tr key={gauge} className={`hover:bg-muted/30 ${selected ? "bg-yellow-50 dark:bg-yellow-950/20 font-semibold" : ""}`}>
                      <td className="py-2.5 px-4 font-bold text-yellow-600 dark:text-yellow-400">{gauge}</td>
                      <td className="py-2.5 px-4 font-mono text-muted-foreground">{res}</td>
                      <td className="py-2.5 px-4 text-foreground font-semibold">{amps}</td>
                      <td className="py-2.5 px-4 text-muted-foreground">{use}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Electrical Voltage Drop Tool for Electricians and Students</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free electrical tool on mobile or desktop to check values quickly, compare scenarios, and support wiring or electronics work.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/voltage-drop-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


